          "string",
          "null"
        ],
        "minLength": 1
      }
    },
    "additionalProperties": false,
    "required": [
      "intent",
      "confidence"
    ]
  }
  ```

{
  "scenario": "intent_recognition",
  "reconstructed_intent": "用户希望查看上季度购买重疾险的客户群体的特征画像，本质是客户分析类意图，应被识别为具体的客户洞察标签而非兜底意图。",
  "judge_basis": "查询语义明确指向客户特征分析，属于常见的营销规划子场景（客户分析）。实际系统输出了泛化的 'other' 意图且置信度仅 0.5，偏离了业务预期。",
  "judge_method": "通过自然语言理解提取用户业务目标，对照营销规划意图体系（基于常识和项目特征）判断意图标签的准确性和置信度的合理性，评估是否满足关键业务期望。",
  "expected": {
    "intent": "customer_analysis",
    "confidence": 0.9,
    "target_value": null,
    "path_types": null,
    "subIntent": null
  },
  "business_expectations": [
    {
      "expectation_id": "意图标签应准确反映用户业务意图",
      "description": "系统输出的意图标签应当与用户真实的营销分析目标一致，对于明确的客户特征查询不应降级为泛化的 ‘other’。",
      "blocking_level": "blocking"
    },
    {
      "expectation_id": "置信度应与查询明确性匹配",
      "description": "当用户查询意图清晰且边界明确时，系统应输出足够高的置信度（如≥0.7），以支持下游决策。",
      "blocking_level": "non-blocking"
    }
  ],
  "fulfillment_assessments": [
    {
      "expectation_id": "意图标签应准确反映用户业务意图",
      "status": "not_fulfilled",
      "evidence": [
        "实际输出 intent 为 'other'，表明系统未能识别出客户分析意图，而将查询归入兜底分类。"
      ]
    },
    {
      "expectation_id": "置信度应与查询明确性匹配",
      "status": "not_fulfilled",
      "evidence": [
        "实际置信度为 0.5，远低于预期的高确定性值，显示系统对自身判断缺乏信心。"
      ]
    }
  ],
  "overall_fulfillment": {
    "status": "not_fulfilled"
  },
  "missing": [],
  "wrong": [
    {
      "field": "intent",
      "expected": "customer_analysis",
      "actual": "other",
      "description": "意图标签错误，应为具体的客户分析意图，实际输出为泛化的兜底意图 'other'。"
    },
    {
      "field": "confidence",
      "expected": ">=0.7",
      "actual": 0.5,
      "description": "置信度过低，未能反映查询的明确性，可能引起下游错误处理或无效回退。"
    }
  ],
  "extra": [],
  "evidence": [
    {
      "source": "run_trace.extracted_output",
      "content": {
        "intent": "other",
        "confidence": 0.5,
        "subIntent": "其他意图"
      }
    }
  ],
  "reasoning_summary": "用户查询明确表达了对特定客户群体进行特征分析的意图，应被归类为 'customer_analysis' 等高相关意图。实际系统输出泛化标签 'other' 且置信度偏低，导致核心业务期望（意图标签准确性）未满足，整体判定为未满足预期。",
  "needs_human_review": false,
  "boundary_decision": {
    "within_evaluable_scope": true
  },
  "evaluation_boundary": {
    "includes": ["single_turn_intent_recognition", "intent_label_correctness", "confidence_appropriateness"],
    "excludes": ["multi_turn_planning", "sse_card_generation", "slot_filling_completeness", "downstream_planning_execution"]
  }
}

